{
  "formal_minutes": {
    "confirmed_decisions": [
      {
        "item": "공개 릴리스 목표",
        "decision": "스모크 테스트가 통과하면 공개 릴리스 목표를 금요일 15:00 KST로 둔다."
      },
      {
        "item": "packageName 불일치 처리",
        "decision": "packageName 불일치가 보이면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 smoke-theme-pack.mjs를 검토한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName 불일치를 무시하도록 바꾸자.",
        "result": "거절됨"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 공개는 내부 스트레치 목표로만 유지한다.",
        "status": "공개 목표 아님"
      }
    ],
    "non_decisions": [
      {
        "item": "README install steps 검토",
        "status": "가능하면 목요일까지 검토하자는 제안만 있었고 담당자는 정해지지 않았다."
      },
      {
        "item": "Hara의 tarball 경로 확인 시점",
        "status": "Minjun의 스모크 결과 게시 후로만 연결됐고 정확한 마감 시각은 정해지지 않았다."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로는 릴리스를 지연시킬 수 있다."
      },
      {
        "risk": "README install steps가 오래되면 릴리스 노트가 사용자를 오도할 수 있다."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한은 누구에게 있는가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 넣을 것인가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST까지",
      "status": "예정",
      "source_certainty": "직접 명시됨"
    },
    {
      "owner": "Doyun",
      "task": "실패 triage 노트를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST까지",
      "status": "예정",
      "source_certainty": "직접 명시됨"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 생성된 tarball 경로를 확인한다.",
      "due": "Minjun 결과 게시 후",
      "status": "조건부 예정",
      "source_certainty": "직접 명시됨"
    }
  ],
  "followup_note": {
    "next_checks": [
      "Minjun의 스모크 결과 공유 여부",
      "Doyun의 failure triage note 작성 여부",
      "Hara의 tarball 경로 확인 여부",
      "README install steps 검토 담당자 지정 여부",
      "최종 릴리스 승인권자",
      "릴리스 노트에 수요일 내부 스트레치 목표를 넣을지 여부"
    ],
    "not_to_invent": [
      "고객명",
      "외부 파트너명",
      "예산",
      "보안 사고",
      "프로덕션 장애",
      "법적 승인 요건",
      "미지정된 담당자",
      "명시되지 않은 마감 시각"
    ]
  },
  "non_invention_rules": [
    "고객, 외부 파트너, 예산, 보안 사고, 프로덕션 장애, 법적 승인 요건은 원문에 없으면 추가하지 않는다.",
    "미지정된 담당자와 명시되지 않은 마감 시각은 추정하지 않는다.",
    "열린 질문의 답을 확정 사실로 바꾸지 않는다.",
    "내부 스트레치 목표를 공개 릴리스 확정으로 승격하지 않는다."
  ]
}
